__d(function(_g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"DIY_GUIDES",{enumerable:!0,get:function(){return s}}),e.matchGuide=function(t){const o=t.toLowerCase();return s.find(t=>`${t.id} ${t.title}`.toLowerCase().split(/[\s-]+/).some(t=>t.length>2&&o.includes(t)))??s[0]};let t=1;const o=(o,l,s,n,h,c)=>({name:o,emoji:l,photo:`https://loremflickr.com/120/120/${s}?lock=${t++}`,price:n,store:h,url:c}),l=t=>`https://www.youtube.com/results?search_query=${encodeURIComponent(t)}`,s=[{id:'wiper-blades',title:'Replace wiper blades',emoji:'\ud83c\udf27\ufe0f',minutes:10,difficulty:'Easy',tools:['New wiper blades (check your size)','A towel'],steps:['Find your blade size in the owner\u2019s manual or measure the old blades \u2014 the driver and passenger sides are often different lengths.','Lift the wiper arm away from the windshield until it locks in the upright position. Lay a folded towel on the glass in case an arm snaps back.','Locate the small plastic tab or clip where the blade meets the arm. Press it in to release the lock.','Slide the old blade down the arm and off the hook, keeping the bare metal arm from hitting the windshield.','Line up the new blade\u2019s connector with the hook and slide it on until you hear or feel it click into place.','Gently lower the arm back onto the glass and give the blade a light tug to confirm it\u2019s locked.','Repeat on the other side, then run the wipers with washer fluid to check for streaks.'],tip:'Replace blades every 6\u201312 months. If they chatter or streak even when new, wipe the rubber edge with a little glass cleaner \u2014 road film is often the culprit.',materials:[o('Wiper blades (pair)','\ud83c\udf27\ufe0f','windshield,wiper','$12.99','AutoZone','https://www.autozone.com/search?searchText=wiper+blades'),o('Glass cleaner','\ud83e\uddf4','glass,cleaner,spray','$3.48','Walmart','https://www.walmart.com/search?q=auto+glass+cleaner')],videoUrl:l('how to replace windshield wiper blades'),videoTitle:'Replace wiper blades in 2 minutes'},{id:'engine-air-filter',title:'Change engine air filter',emoji:'\ud83c\udf43',minutes:15,difficulty:'Easy',tools:['New engine air filter','Flat screwdriver (sometimes)','Shop towel'],steps:['With the engine off and cool, open the hood and locate the air filter box \u2014 usually a large black plastic box near the front, connected to a wide duct.','Release the housing clips or unscrew the fasteners holding the lid. Some boxes use spring clips you flip up by hand.','Lift the lid and note exactly how the old filter sits (which side faces the engine) before removing it.','Pull out the old filter and wipe any leaves or dirt from inside the empty box with a shop towel.','Seat the new filter in the same orientation, making sure the rubber sealing edge sits flush all around.','Close the lid and re-secure every clip or screw \u2014 a loose lid lets in unfiltered air.','Close the hood and you\u2019re done.'],tip:'Hold the old filter up to a light. If light barely passes through, it was overdue. Most cars want a new one every 15,000\u201330,000 miles, sooner in dusty areas.'},{id:'cabin-air-filter',title:'Replace cabin air filter',emoji:'\ud83d\ude2e\u200d\ud83d\udca8',minutes:15,difficulty:'Easy',tools:['New cabin air filter','Owner\u2019s manual (for location)'],steps:['Check your manual for the cabin filter location \u2014 most sit behind the glovebox; some are under the hood near the windshield.','For a glovebox filter, empty the glovebox, then squeeze its sides or release the stop arms so it drops down fully.','Behind it you\u2019ll see a rectangular plastic cover. Unclip or slide it off to expose the filter.','Slide the old filter out, watching for an airflow arrow printed on its frame.','Insert the new filter so its airflow arrow points the same direction the old one did (usually downward).','Refit the cover and snap the glovebox back into its normal position.','Run the fan on high for a minute to confirm strong, odor-free airflow.'],tip:'A clogged cabin filter causes weak A/C airflow and musty smells. Replace it about once a year or every 15,000 miles.',materials:[o('Cabin air filter','\ud83d\ude2e\u200d\ud83d\udca8','car,air,filter','$8.99','Amazon','https://www.amazon.com/s?k=cabin+air+filter')],videoUrl:l('how to replace cabin air filter behind glovebox'),videoTitle:'Replace a cabin air filter (glovebox)'},{id:'tire-pressure',title:'Check & top up tire pressure',emoji:'\ud83d\udede',minutes:15,difficulty:'Easy',tools:['Tire pressure gauge','Air pump or gas-station air machine'],steps:['Check pressures when tires are cold (driven less than a mile). Find the recommended PSI on the sticker inside the driver\u2019s door jamb \u2014 not the number on the tire sidewall.','Unscrew the valve cap on the first tire and keep it somewhere safe.','Press the gauge firmly onto the valve stem until the hissing stops and read the PSI.','If it\u2019s low, attach the air hose and add air in short bursts, re-checking with the gauge as you go.','If it\u2019s over the target, press the small pin inside the valve to let a little air out, then re-check.','Set all four tires to the recommended PSI and reinstall every valve cap.','Don\u2019t forget the spare if your car has one \u2014 check it a few PSI above normal since it sits unused.'],tip:'Tires lose about 1 PSI per month and 1 PSI for every 10\xb0F temperature drop. Properly inflated tires last longer and improve fuel economy.'},{id:'washer-fluid',title:'Top up windshield washer fluid',emoji:'\ud83d\udca6',minutes:5,difficulty:'Easy',tools:['Washer fluid (not plain water)','Funnel (optional)'],steps:['Open the hood and find the washer reservoir cap \u2014 it\u2019s marked with a windshield/water symbol and usually has a blue or white cap.','Pop the cap off. Most reservoirs are translucent so you can see the current fluid level.','Place a funnel in the opening if you have one, to avoid spills onto hot engine parts.','Pour in washer fluid until it reaches the \u201cfull\u201d line or nears the top of the neck.','In freezing climates, use a winter-rated fluid so it won\u2019t freeze and crack the reservoir.','Press the cap back on firmly until it clicks, then test the sprayers and wipers.'],tip:'Avoid plain water \u2014 it freezes, grows algae, and doesn\u2019t cut through bug splatter. Dedicated washer fluid is cheap and works in all seasons.'},{id:'oil-level',title:'Check engine oil level',emoji:'\ud83d\udee2\ufe0f',minutes:10,difficulty:'Easy',tools:['Clean paper towel or rag','Engine oil (only if topping up)'],steps:['Park on level ground and turn the engine off. Wait 5\u201310 minutes so the oil drains back into the pan for an accurate reading.','Open the hood and pull out the dipstick \u2014 it usually has a brightly colored loop handle.','Wipe the dipstick clean with a paper towel, then fully reinsert it and pull it out again.','Read where the oil film ends. It should sit between the two marks (MIN and MAX, or hatched area).','Check the color too \u2014 amber is healthy; very dark or gritty oil suggests it\u2019s due for a change.','If the level is at or below MIN, add a small amount of the correct oil through the filler cap, then re-check. Add gradually \u2014 overfilling is harmful.','Reinsert the dipstick fully and close the hood.'],tip:'Check your oil once a month and before long road trips. Never add more than needed to reach MAX \u2014 too much oil can foam and damage seals.'},{id:'key-fob-battery',title:'Replace key fob battery',emoji:'\ud83d\udd11',minutes:10,difficulty:'Easy',tools:['New coin battery (often CR2032)','Small flat screwdriver','Tape (optional)'],steps:['If your fob hides a metal emergency key, slide it out \u2014 many fobs split open using that key as a lever.','Find the seam around the fob\u2019s edge and gently pry it apart with a small flat screwdriver wrapped in tape to avoid scratches.','Note the battery model printed on the old cell (commonly CR2032) and which side faces up (+ symbol).','Pop out the old battery without bending the metal contacts.','Drop in the new battery the same way up \u2014 positive (+) side matching the old one \u2014 and avoid touching both faces with your fingers.','Press the two halves back together until the seam clicks shut, then reinsert the emergency key if applicable.','Test lock, unlock, and panic buttons from a few feet away.'],tip:'If the fob still feels weak after a fresh battery, the button contacts may be worn \u2014 but a dying battery is by far the most common cause of short range.'},{id:'jump-start',title:'Jump-start a dead battery',emoji:'\ud83d\udd0b',minutes:20,difficulty:'Medium',tools:['Jumper cables or a portable jump pack','A working donor vehicle (for cables)','Gloves & eye protection'],steps:['Park the working car nose-to-nose with the dead one, close but not touching. Turn both engines off and set both parking brakes.','Identify the battery terminals: red/\u201c+\u201d is positive, black/\u201c\u2013\u201d is negative.','Clamp one RED cable to the dead battery\u2019s positive (+) terminal, then the other RED end to the good battery\u2019s positive (+) terminal.','Clamp one BLACK cable to the good battery\u2019s negative (\u2013) terminal. Connect the final BLACK clamp to a bare metal bolt or bracket on the dead car\u2019s engine \u2014 NOT to its battery \u2014 to avoid sparks near the battery.','Start the working car and let it run for 2\u20133 minutes to feed charge into the dead battery.','Try starting the dead car. If it cranks slowly, wait another few minutes and try again.','Once it starts, remove the clamps in reverse order: black from the engine ground, black from the good battery, red from the good battery, red from the revived battery.','Drive the revived car for at least 20\u201330 minutes so the alternator can recharge the battery.'],tip:'If the battery dies again soon after, it likely needs replacing or you left something on. Never let the two cars\u2019 bodies touch, and never connect the final black clamp directly to the dead battery\u2019s negative post.'},{id:'boiling-water-dent',title:'Boiling water dent method',emoji:'\u2668\ufe0f',minutes:15,difficulty:'Easy',tools:['Kettle or pot of boiling water','Rubber gloves','Cup-style plunger','A towel'],steps:['Confirm the dent is on a flexible plastic panel (most bumpers) with intact paint \u2014 this method is for plastic, not creased steel.','Boil a kettle or pot of water and put on rubber gloves to protect your hands from the heat.','Pour the boiling water slowly over the dented area so the plastic warms and becomes pliable.','Working quickly while it is still hot, reach behind the panel and push the dent outward with your hand.','If you can\u2019t reach behind it, press a clean cup-style plunger over the dent and pull firmly to draw it out.','Pour a little cold water over the area to set the plastic in its restored shape.','Repeat once or twice if a shallow dent remains. Deep creases may still need a body shop.'],tip:'Works best on warm days and on bumpers where the plastic flexes. It will not fix dents with cracked or chipped paint.',materials:[o('Rubber dish gloves','\ud83e\udde4','rubber,gloves','$5.98','Walmart','https://www.walmart.com/search?q=rubber+gloves'),o('Cup-style plunger','\ud83e\udea0','plunger,rubber','$6.97','Home Depot','https://www.homedepot.com/s/cup%20plunger'),o('Electric kettle','\u2668\ufe0f','electric,kettle','$14.99','Amazon','https://www.amazon.com/s?k=electric+kettle')],videoUrl:l('how to fix car bumper dent with boiling water'),videoTitle:'How to pop a bumper dent with boiling water'},{id:'plunger-dent',title:'Plunger pull method',emoji:'\ud83e\udea0',minutes:12,difficulty:'Medium',tools:['Clean cup-style plunger (not a flanged toilet plunger)','Water','A towel'],steps:['Pick a clean cup-style sink plunger. The dent should be wider than the cup but inside a smooth, flat area.','Lightly wet both the dent and the rim of the plunger cup so it can form a tight seal.','Center the plunger over the dent and press in firmly to push out the air and create suction.','Pull straight outward with steady force \u2014 you should feel or hear the panel pop back.','Repeat, re-wetting the seal as needed, until the surface is level.','Dry the area and inspect in good light; small high spots can be tapped gently from behind.'],tip:'Keep the pull straight, not at an angle, or the seal breaks. A sharp crease likely needs paintless dent repair by a pro.',materials:[o('Cup-style sink plunger','\ud83e\udea0','plunger,cup','$6.97','Home Depot','https://www.homedepot.com/s/cup%20plunger'),o('Microfiber towel','\ud83e\uddfd','microfiber,cloth','$1.97','Walmart','https://www.walmart.com/search?q=microfiber+towel')],videoUrl:l('how to remove car dent with plunger'),videoTitle:'Pull a door/panel dent with a plunger'},{id:'scratch-buff',title:'Buff out a light scratch',emoji:'\u2728',minutes:20,difficulty:'Easy',tools:['Car wash soap & water','Microfiber cloths','Scratch-removal compound or polish','Optional: car wax'],steps:['Wash and dry the scratched area so grit doesn\u2019t grind into the paint while you work.','Run a fingernail across the scratch. If it doesn\u2019t catch, it\u2019s in the clear coat and can usually be buffed out.','Apply a small amount of scratch-removal compound to a clean, damp microfiber cloth.','Rub the compound over the scratch with firm, even strokes for 30\u201360 seconds, following the scratch direction.','Wipe away the residue with a clean cloth and check progress in good light.','Repeat two or three times for stubborn marks; finish with a coat of wax to seal and protect the area.'],tip:'If your nail catches the scratch, it has gone through the clear coat and needs touch-up paint or a shop \u2014 buffing alone won\u2019t fill it.',materials:[o('Scratch & swirl remover','\ud83e\uddf4','car,polish,bottle','$7.97','AutoZone','https://www.autozone.com/search?searchText=scratch+remover'),o('Microfiber cloths (6pk)','\ud83e\uddfd','microfiber,cloths','$6.99','Amazon','https://www.amazon.com/s?k=microfiber+cloth'),o('Car wax','\u2728','car,wax','$8.47','Walmart','https://www.walmart.com/search?q=car+wax')],videoUrl:l('how to buff out car scratch clear coat'),videoTitle:'Buff a light clear-coat scratch by hand'}]},802,[]);
